import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useCarrito } from '../../contexto/CarritoContexto';
import { useScrollReveal, usePaquetesReveal } from '../compartidos/useScrollReveal';
import { useToast } from '../compartidos/useToast';
import NavegacionPrincipal from '../compartidos/NavegacionPrincipal';
import BarraEntrega from '../compartidos/BarraEntrega';
import RedesSocialesFlotantes from '../compartidos/RedesSocialesFlotantes';
import { DATOS_GALERIA, DATOS_FAQ, DATOS_RESEÑAS_INICIALES } from '../../datos/datos';
import { obtenerProductosAPI, obtenerCategoriasAPI, obtenerPaquetesAPI, obtenerOpinionesAPI, crearOpinionAPI } from '../../servicios/api';

export default function PaginaInicio() {
  const navigate = useNavigate();
  const { agregarItem } = useCarrito();
  const { toastMensaje, toastVisible, mostrarToast } = useToast();
  useScrollReveal();
  usePaquetesReveal();

  // Galería
  const [filtroGaleria, setFiltroGaleria] = useState('todos');
  const [lightboxAbierto, setLightboxAbierto] = useState(false);
  const [indiceLightbox, setIndiceLightbox] = useState(0);
  const [modalVideoAbierto, setModalVideoAbierto] = useState(false);
  const [videoActual, setVideoActual] = useState({ src: '', titulo: '', categoria: '' });
  const videoRef = useRef(null);

  // Productos y Categorías
  const [modalProductoAbierto, setModalProductoAbierto] = useState(false);
  const [productoActivo, setProductoActivo] = useState(null);
  const [indiceImagenProducto, setIndiceImagenProducto] = useState(0);

  // Formulario de pedido (modal intermedio)
  const [modalFormularioPedido, setModalFormularioPedido] = useState(false);
  const [productoPedido, setProductoPedido] = useState(null);
  const [formularioPedido, setFormularioPedido] = useState({
    nombreCompleto: '',
    telefono: '',
    correoElectronico: '',
    nombreDestinatario: '',
    personalizacion: '',
  });
  const [enviandoPedido, setEnviandoPedido] = useState(false);

  // FAQ
  const [faqAbierta, setFaqAbierta] = useState(null);

  // Reseñas
  const [reseñas, setReseñas] = useState(DATOS_RESEÑAS_INICIALES);
  const [mostrarNombre, setMostrarNombre] = useState(true);
  const [formReseña, setFormReseña] = useState({ nombre: '', calificacion: '', texto: '' });
  const [contadorTexto, setContadorTexto] = useState(0);

  // Datos API
  const [productosAPI, setProductosAPI] = useState([]);
  const [categoriasAPI, setCategoriasAPI] = useState([]);
  const [paquetesAPI, setPaquetesAPI] = useState([]);
  const [cargandoTienda, setCargandoTienda] = useState(true);

  // Scroll parallax hero
  useEffect(() => {
    const onScroll = () => {
      const fondo = document.getElementById('heroFondo');
      if (fondo) fondo.style.transform = `translateY(${window.scrollY * 0.25}px)`;
    };
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Cargar datos de la tienda
  useEffect(() => {
    const cargarTodo = async () => {
      try {
        const [resProd, resCat, resPaq, resOpiniones] = await Promise.all([obtenerProductosAPI(), obtenerCategoriasAPI(), obtenerPaquetesAPI(), obtenerOpinionesAPI().catch(() => [])]);
        setProductosAPI(resProd);
        setCategoriasAPI(resCat);
        // Filtrar solo paquetes activos y mapear a formato del componente
        const paquetesActivos = (resPaq || []).filter(p => p.Activo).map((p, i) => ({
          nombre: p.Nombre_Paquete || 'Sin nombre',
          precio: Number(p.Precio_Paquete) || 0,
          imagen: p.Imagen_Paquete || 'https://images.unsplash.com/photo-1452587925148-ce544e77e70d?w=600&q=80',
          etiqueta: p.Descripcion_Paquete ? p.Descripcion_Paquete.substring(0, 40) : 'Paquete fotográfico',
          descripcion: p.Descripcion_Paquete || 'Paquete de fotografía profesional.',
          numero: String(i + 1).padStart(2, '0'),
          beneficios: (p.Descripcion_Paquete || '').split('.').filter(b => b.trim()).slice(0, 4).map(b => b.trim()),
          entrega: 'Entrega: 5 a 10 días hábiles',
          derecha: i % 2 !== 0,
          destacado: i === 2,
          idBackend: p.Id_Paquete
        }));
        setPaquetesAPI(paquetesActivos);

        // Mapear reseñas de API
        if (resOpiniones && resOpiniones.length > 0) {
          const apiReseñas = resOpiniones.map(o => {
             const iniciales = (o.Nombre_Usuario || 'Anónimo').split(' ').map(p=>p[0]).join('').toUpperCase().substring(0,2);
             return {
                nombre: o.Nombre_Usuario || 'Anónimo',
                iniciales: iniciales || '👤',
                estrellas: o.Calificacion || 5,
                texto: o.Comentario || '',
                fecha: new Date(o.Fecha).toLocaleDateString(),
                color: ['#ff0844', '#800020']
             };
          });
          setReseñas(apiReseñas);
        }

      } catch (error) {
        console.error('Error al cargar tienda:', error);
      } finally {
        setCargandoTienda(false);
      }
    };
    cargarTodo();
  }, []);

  // Teclado lightbox / modal video / modal producto
  useEffect(() => {
    const onKey = (e) => {
      if (lightboxAbierto) {
        if (e.key === 'ArrowLeft') navLightbox(-1);
        if (e.key === 'ArrowRight') navLightbox(1);
        if (e.key === 'Escape') cerrarLightbox();
      }
      if (modalVideoAbierto && e.key === 'Escape') cerrarModalVideo();
      if (modalProductoAbierto) {
        if (e.key === 'ArrowLeft') navImagenProducto(-1);
        if (e.key === 'ArrowRight') navImagenProducto(1);
        if (e.key === 'Escape') cerrarModalProducto();
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [lightboxAbierto, modalVideoAbierto, modalProductoAbierto, indiceLightbox, indiceImagenProducto, productoActivo]);

  /* ── GALERÍA ── */
  const itemsLightbox = filtroGaleria === 'todos'
    ? DATOS_GALERIA.filter(i => i.type !== 'video')
    : DATOS_GALERIA.filter(i => i.category === filtroGaleria && i.type !== 'video');

  const itemsFiltrados = filtroGaleria === 'todos'
    ? DATOS_GALERIA
    : DATOS_GALERIA.filter(i => i.category === filtroGaleria);

  const categorias = ['todos', ...new Set(DATOS_GALERIA.map(i => i.category))];

  const abrirLightbox = (idx) => {
    setIndiceLightbox(idx);
    setLightboxAbierto(true);
    document.body.style.overflow = 'hidden';
  };

  const cerrarLightbox = () => {
    setLightboxAbierto(false);
    document.body.style.overflow = '';
  };

  const navLightbox = (d) => {
    setIndiceLightbox(prev => (prev + d + itemsLightbox.length) % itemsLightbox.length);
  };

  const abrirModalVideo = (src, titulo, categoria) => {
    setVideoActual({ src, titulo, categoria });
    setModalVideoAbierto(true);
    document.body.style.overflow = 'hidden';
    setTimeout(() => {
      if (videoRef.current) { videoRef.current.load(); videoRef.current.play().catch(() => { }); }
    }, 100);
  };

  const cerrarModalVideo = () => {
    if (videoRef.current) { videoRef.current.pause(); videoRef.current.src = ''; }
    setModalVideoAbierto(false);
    document.body.style.overflow = '';
  };

  /* ── PRODUCTOS ── */
  const abrirModalProducto = (id) => {
    const producto = productosAPI.find(p => p.Id_Producto === id);
    if (!producto) return;

    const prodNormalizado = {
      Id_Producto: producto.Id_Producto,
      nombre: producto.Nombre_Producto,
      precio: producto.Precio_Producto,
      imagenes: [producto.Imagen, ...(producto.Imagenes_Adicionales || [])].filter(Boolean)
    };

    setProductoActivo(prodNormalizado);
    setIndiceImagenProducto(0);
    setModalProductoAbierto(true);
    document.body.style.overflow = 'hidden';
  };

  const cerrarModalProducto = () => {
    setModalProductoAbierto(false);
    document.body.style.overflow = '';
    setProductoActivo(null);
  };

  const navImagenProducto = (d) => {
    if (!productoActivo) return;
    setIndiceImagenProducto(prev => (prev + d + productoActivo.imagenes.length) % productoActivo.imagenes.length);
  };

  const abrirFormularioPedido = (producto) => {
    setProductoPedido(producto);
    setFormularioPedido({
      nombreCompleto: '',
      telefono: '',
      correoElectronico: '',
      nombreDestinatario: '',
      personalizacion: '',
    });
    setModalFormularioPedido(true);
    document.body.style.overflow = 'hidden';
  };

  const cerrarFormularioPedido = () => {
    setModalFormularioPedido(false);
    document.body.style.overflow = '';
    setProductoPedido(null);
  };

  const enviarFormularioPedido = async () => {
    if (!formularioPedido.nombreCompleto.trim()) {
      mostrarToast('⚠️ Ingresa tu nombre completo');
      return;
    }
    if (!formularioPedido.telefono.trim()) {
      mostrarToast('⚠️ Ingresa tu número de teléfono');
      return;
    }

    setEnviandoPedido(true);
    try {
      const datosCliente = {
        nombreCompleto: formularioPedido.nombreCompleto.trim(),
        telefono: formularioPedido.telefono.trim(),
        correoElectronico: formularioPedido.correoElectronico.trim(),
        nombreDestinatario: formularioPedido.nombreDestinatario.trim(),
        personalizacion: formularioPedido.personalizacion.trim(),
      };

      const exito = await agregarItem(productoPedido.Id_Producto || productoPedido.id, 1, datosCliente);
      if (exito) {
        cerrarFormularioPedido();
        cerrarModalProducto();
        mostrarToast('✅ Producto agregado al carrito');
        setTimeout(() => navigate('/carrito'), 600);
      }
    } catch (err) {
      mostrarToast('⚠️ Error al agregar al carrito');
    } finally {
      setEnviandoPedido(false);
    }
  };

  const pedirProducto = (id) => {
    const prod = productosAPI.find(p => p.Id_Producto === id);
    if (prod) {
      abrirFormularioPedido({ Id_Producto: prod.Id_Producto, nombre: prod.Nombre_Producto, precio: prod.Precio_Producto, imagen: prod.Imagen });
    }
  };

  const pedirProductoModal = () => {
    if (!productoActivo) return;
    abrirFormularioPedido(productoActivo);
  };

  /* ── PAQUETES ── */
  const seleccionarPaquete = (paquete) => {
    localStorage.setItem('cdl_cita_previa', JSON.stringify({ nombre: paquete.nombre, precio: paquete.precio, imagen: paquete.imagen }));
    navigate('/citas');
  };

  /* ── RESEÑAS ── */
  const enviarReseña = async () => {
    if (!formReseña.calificacion) { mostrarToast('⚠️ Selecciona una calificación'); return; }
    if (!formReseña.texto.trim()) { mostrarToast('⚠️ Escribe tu opinión'); return; }
    const nombreUsuario = mostrarNombre ? (formReseña.nombre.trim() || 'Anónimo') : 'Anónimo';

    try {
      await crearOpinionAPI({
        nombre: nombreUsuario,
        calificacion: parseInt(formReseña.calificacion),
        comentario: formReseña.texto.trim()
      });

      const iniciales = nombreUsuario === 'Anónimo' ? '👤' : nombreUsuario.split(' ').map(p => p[0]).join('').toUpperCase().substring(0, 2);
      setReseñas(prev => [{ nombre: nombreUsuario, iniciales, estrellas: parseInt(formReseña.calificacion), texto: formReseña.texto.trim(), fecha: 'Ahora mismo', color: ['#ff0844', '#800020'] }, ...prev]);

      mostrarToast('⭐ ¡Opinión publicada con éxito!');
      setFormReseña({ nombre: '', calificacion: '', texto: '' });
      setContadorTexto(0);
    } catch (error) {
      mostrarToast('⚠️ Error al publicar opinión');
    }
  };

  const itemLightboxActual = itemsLightbox[indiceLightbox];

  return (
    <div>
      <BarraEntrega mostrarToast={mostrarToast} />
      <NavegacionPrincipal />

      {/* ── HERO ── */}
      <section className="seccion-hero" id="hero">
        <div className="hero-fondo" id="heroFondo"></div>
        <div className="hero-degradado"></div>
        <div className="hero-viñeta"></div>
        <div className="hero-cuadricula"></div>
        <div className="hero-esquina top-left"></div>
        <div className="hero-esquina top-right"></div>
        <div className="hero-esquina bottom-left"></div>
        <div className="hero-esquina bottom-right"></div>
        <div className="hero-polaroids-flotantes">
          <div className="foto-polaroid p1"><img src="https://images.unsplash.com/photo-1519167758481-83f550bb49b3?w=200&q=75" alt="Boda" /></div>
          <div className="foto-polaroid p2"><img src="https://images.unsplash.com/photo-1537633552985-df8429e8048b?w=200&q=75" alt="Evento" /></div>
          <div className="foto-polaroid p3"><img src="https://images.unsplash.com/photo-1492691527719-9d1e07e534b4?w=200&q=75" alt="Fotografía" /></div>
          <div className="foto-polaroid p4"><img src="https://images.unsplash.com/photo-1607344645866-009c320b63e0?w=200&q=75" alt="Producto" /></div>
        </div>
        <div className="hero-contenido">
          <div className="hero-subtitulo-superior"><span className="punto-animado"></span>Communicating Design Lion &nbsp;·&nbsp; Bogotá, Colombia</div>
          <h1 className="hero-titulo">
            <span className="linea-normal">Convertimos tus momentos</span>
            <span className="linea-enfasis">en recuerdos</span>
            <span className="linea-normal">que perduran toda la vida</span>
          </h1>
          <p className="hero-descripcion">No solo capturamos momentos, los convertimos en experiencias únicas con fotografía y video.</p>
          <div className="hero-botones">
            <a className="boton-primario" onClick={() => document.querySelector('#packages')?.scrollIntoView({ behavior: 'smooth' })} style={{ cursor: 'pointer' }}>Ver Paquetes</a>
            <a className="boton-secundario" onClick={() => document.querySelector('#gallery')?.scrollIntoView({ behavior: 'smooth' })} style={{ cursor: 'pointer' }}>Explorar Galería</a>
          </div>
        </div>
        <div className="hero-indicador-scroll"><span className="indicador-scroll-texto"></span><div className="indicador-scroll-barra"></div></div>
        <div className="hero-barra-estadisticas">
          <div className="estadistica-item"><div className="estadistica-numero">4K+</div><div className="estadistica-etiqueta">Calidad Visual</div></div>
          <div className="estadistica-item"><div className="estadistica-numero">100%</div><div className="estadistica-etiqueta">Diseño Personalizado</div></div>
          <div className="estadistica-item"><div className="estadistica-numero">5★</div><div className="estadistica-etiqueta">Experiencia Premium</div></div>
          <div className="estadistica-item"><div className="estadistica-numero">BOG</div><div className="estadistica-etiqueta">Bogotá, Colombia</div></div>
        </div>
      </section>

      {/* ── SERVICIOS ── */}
      <section className="seccion-servicios" id="services">
        <div className="servicios-encabezado animar-entrada">
          <h2>Nuestros Servicios</h2>
          <p>No es solo una imagen o una foto, sino un recuerdo que te permite revivir ese momento especial una y otra vez.</p>
        </div>
        <div className="servicios-cuadricula">
          {[
            { icono: 'fa-camera', titulo: 'Tecnología de Última Generación', desc: 'Servicios de alta calidad especializados en capturar los momentos más importantes con equipos de última tecnología.', items: ['Drones especializados de captura cinematográfica', 'Cámaras UHD de fotografía y grabación', 'Cámaras Phantom para cámara lenta', 'Iluminación específica para cada captura', 'Bases giratorias para tomas dinámicas'] },
            { icono: 'fa-video', titulo: 'Edición de Video Avanzada', desc: 'Edición con efectos tridimensionales y cinematográficos, creando una experiencia visual única y de alto impacto.', items: ['Adobe After Effects y 3DS Max Studio', 'Efectos especiales de última generación', 'Estilo visual cinematográfico', 'Múltiples resoluciones y calidades', 'Resultados poligonales de alto impacto'], delay: '0.1s' },
            { icono: 'fa-box-open', titulo: 'Contenedores Temáticos', desc: 'Contenedores personalizados diseñados con gran detalle para crear un elemento único que exhibirás con orgullo.', items: ['Diseño según temática del evento', 'Materiales de alta calidad y texturización real', 'Experiencia interactiva al abrir', 'Exposición en forma de diorama', 'Opción a incluir figura de crochet'], delay: '0.2s' },
          ].map((s, i) => (
            <div key={i} className="tarjeta-servicio animar-entrada" style={s.delay ? { transitionDelay: s.delay } : {}}>
              <i className={`fas ${s.icono} servicio-icono`}></i>
              <div className="tarjeta-servicio-titulo">{s.titulo}</div>
              <p className="tarjeta-servicio-descripcion">{s.desc}</p>
              <ul className="servicio-caracteristicas">
                {s.items.map((it, j) => <li key={j}><i className="fas fa-check"></i> {it}</li>)}
              </ul>
            </div>
          ))}
        </div>
      </section>

      {/* ── PAQUETES ── */}
      <SeccionPaquetes paquetes={paquetesAPI} onSeleccionar={seleccionarPaquete} />

      {/* ── GALERÍA ── */}
      <section className="seccion-galeria seccion-espaciado" id="gallery">
        <div className="contenedor">
          <div className="encabezado-seccion animar-entrada">
            <span className="etiqueta-seccion">Trabajos</span>
            <h2 className="titulo-seccion">NUESTRA <span>GALERÍA</span></h2>
            <p className="subtitulo-seccion">Proyectos que hablan por sí solos.</p>
          </div>
          <div className="galeria-filtros" id="galeriaFiltros">
            {categorias.map(c => (
              <button key={c} className={`boton-filtro${filtroGaleria === c ? ' active' : ''}`} onClick={() => setFiltroGaleria(c)}>
                {c.charAt(0).toUpperCase() + c.slice(1)}
              </button>
            ))}
          </div>
          <div className="galeria-mosaico" id="galeriaMosaico">
            {itemsFiltrados.map((item, idx) => {
              if (item.type === 'video') return (
                <div key={idx} className="galeria-item item-video" onClick={() => abrirModalVideo(item.src, item.title, item.category)}>
                  <div className="video-miniatura-contenedor">
                    <video src={`${item.src}#t=0.5`} preload="metadata" muted playsInline></video>
                    <div className="video-boton-reproducir"><i className="fas fa-play"></i></div>
                    <div className="video-insignia"><i className="fas fa-film"></i> Video</div>
                  </div>
                  <div className="galeria-item-overlay">
                    <div className="galeria-item-categoria">{item.category}</div>
                    <div className="galeria-item-titulo">{item.title}</div>
                  </div>
                </div>
              );
              const lbIdx = itemsLightbox.indexOf(item);
              if (item.type === 'especial') return (
                <div key={idx} className="galeria-item item-especial" onClick={() => abrirLightbox(lbIdx)}>
                  <img src={item.src} alt={item.title} loading="lazy" />
                  <div className="insignia-especial"><i className="fas fa-heart"></i> Especial</div>
                  <div className="galeria-item-overlay"><div className="galeria-item-categoria">{item.category}</div><div className="galeria-item-titulo">{item.title}</div></div>
                  <div className="galeria-icono-expandir"><i className="fas fa-expand-alt"></i></div>
                </div>
              );
              return (
                <div key={idx} className="galeria-item" onClick={() => abrirLightbox(lbIdx)}>
                  <img src={item.src} alt={item.title} loading="lazy" />
                  <div className="galeria-item-overlay"><div className="galeria-item-categoria">{item.category}</div><div className="galeria-item-titulo">{item.title}</div></div>
                  <div className="galeria-icono-expandir"><i className="fas fa-expand-alt"></i></div>
                </div>
              );
            })}
          </div>
        </div>
      </section>

      {/* Lightbox */}
      <div className={`lightbox-fondo${lightboxAbierto ? ' open' : ''}`} id="lightboxFondo">
        <button className="lightbox-boton-cerrar" onClick={cerrarLightbox}>×</button>
        <button className="lightbox-navegacion prev" onClick={() => navLightbox(-1)}>‹</button>
        {itemLightboxActual && (
          <>
            <img className="lightbox-imagen" id="lightboxImagen" src={itemLightboxActual.src} alt={itemLightboxActual.title} />
            {itemLightboxActual.dedicatoria ? (
              <div className={`lightbox-dedicatoria${lightboxAbierto ? ' visible' : ''}`} id="lightboxDedicatoria">
                <span className="dedicatoria-icono">♥</span>
                <p className="dedicatoria-texto">{itemLightboxActual.dedicatoria}</p>
                <div className="dedicatoria-linea"></div>
              </div>
            ) : (
              <div className="lightbox-informacion" id="lightboxInformacion">
                {itemLightboxActual.title} · {itemLightboxActual.category} · {indiceLightbox + 1} / {itemsLightbox.length}
              </div>
            )}
          </>
        )}
        <button className="lightbox-navegacion next" onClick={() => navLightbox(1)}>›</button>
      </div>

      {/* Modal Video */}
      <div className={`modal-video-fondo${modalVideoAbierto ? ' open' : ''}`} id="modalVideoFondo" onClick={(e) => e.target.id === 'modalVideoFondo' && cerrarModalVideo()}>
        <div className="modal-video-caja">
          <button className="modal-video-boton-cerrar" onClick={cerrarModalVideo}>×</button>
          <video ref={videoRef} controls playsInline preload="metadata"></video>
          <div className="modal-video-informacion">
            <div>
              <div className="modal-video-categoria" id="modalVideoCategoria">{videoActual.categoria}</div>
              <div className="modal-video-titulo" id="modalVideoTitulo">{videoActual.titulo}</div>
            </div>
          </div>
        </div>
      </div>

      {/* ── PRODUCTOS POR CATEGORÍA ── */}
      <section className="seccion-productos seccion-espaciado" id="products">
        <div className="contenedor">
          <div className="encabezado-seccion animar-entrada" style={{ marginBottom: '5rem' }}>
            <h2 className="titulo-seccion">NUESTROS <span>PRODUCTOS</span></h2>
          </div>

          {cargandoTienda ? (
            <div style={{ color: 'var(--text-secondary)', textAlign: 'center', padding: '4rem 0' }}>Cargando catálogo...</div>
          ) : (
            categoriasAPI.filter(cat => cat.Activo !== false && cat.Activo !== 0).map((cat) => {
              const productosDeCat = productosAPI.filter(p => 
                p.Id_Categoria == cat.Id_Categoria && 
                (p.Activo !== false && p.Activo !== 0)
              );
              if (productosDeCat.length === 0) return null;

              return (
                <div key={cat.Id_Categoria} className="categoria-grupo" style={{ marginBottom: '6rem' }}>
                  <div className="encabezado-categoria animar-entrada" style={{ marginBottom: '2.5rem', textAlign: 'center' }}>
                    <span className="etiqueta-seccion">{cat.Nombre_Categoria}</span>
                    <p className="subtitulo-seccion" style={{ marginTop: '0.5rem' }}>{cat.Descripcion_Categoria}</p>
                  </div>

                  <div className="productos-cuadricula">
                    {productosDeCat.map(p => (
                      <div key={p.Id_Producto} className="tarjeta-producto animar-entrada">
                        <div className="producto-imagen-contenedor" onClick={() => abrirModalProducto(p.Id_Producto)}>
                          <img 
                            className="producto-imagen" 
                            src={p.imagenUrl || p.Imagen || p.Imagen_Producto} 
                            alt={p.Nombre_Producto} 
                            loading="lazy"
                            onError={e => { e.target.src = 'https://images.unsplash.com/photo-1513475382585-d06e58bcb0e0?w=700&q=80'; }} 
                          />
                          <div className="producto-imagen-overlay"></div>
                          <div className="producto-precio-etiqueta">
                            <span className="producto-precio-monto">${Number(p.Precio_Producto).toLocaleString('es-CO')}</span>
                          </div>
                        </div>
                        <div className="producto-informacion">
                          <div className="producto-nombre">{p.Nombre_Producto}</div>
                          <button className="producto-boton-agregar" style={{ width: '100%', borderRadius: '50px' }} onClick={() => pedirProducto(p.Id_Producto)}>
                            <i className="fas fa-bolt"></i> Pedir Ahora
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })
          )}

          {!cargandoTienda && (categoriasAPI.length === 0 || productosAPI.length === 0) && (
            <div style={{ color: 'var(--text-secondary)', textAlign: 'center', padding: '4rem 0' }}>No hay productos disponibles por ahora.</div>
          )}
        </div>
      </section>

      {/* Modal Producto */}
      <div className={`modal-producto-fondo${modalProductoAbierto ? ' active' : ''}`} id="modalProductoFondo">
        <div className="modal-producto-caja">
          <button className="modal-boton-cerrar" onClick={cerrarModalProducto}>
            <svg viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
          </button>
          {productoActivo && (
            <div className="modal-disposicion">
              <div className="modal-galeria">
                <img className="modal-imagen-principal" id="modalImagenPrincipal" src={productoActivo.imagenes[indiceImagenProducto]} alt={productoActivo.nombre} />
                <button className="modal-boton-navegacion prev" onClick={() => navImagenProducto(-1)}>
                  <svg viewBox="0 0 24 24"><polyline points="15 18 9 12 15 6" /></svg>
                </button>
                <button className="modal-boton-navegacion next" onClick={() => navImagenProducto(1)}>
                  <svg viewBox="0 0 24 24"><polyline points="9 18 15 12 9 6" /></svg>
                </button>
                <div className="modal-contador-imagenes">{indiceImagenProducto + 1} / {productoActivo.imagenes.length}</div>
              </div>
              <div className="modal-detalles">
                <div>
                  <div className="modal-nombre-producto">{productoActivo.nombre}</div>
                  <div className="modal-precio-producto">${productoActivo.precio.toLocaleString('es-CO')}</div>
                  <div className="modal-miniaturas">
                    {productoActivo.imagenes.map((img, i) => (
                      <div key={i} className={`modal-miniatura${i === indiceImagenProducto ? ' active' : ''}`} onClick={() => setIndiceImagenProducto(i)}>
                        <img src={img} alt="" />
                      </div>
                    ))}
                  </div>
                </div>
                <div className="modal-grupo-botones">
                  <button className="modal-boton-pedir" onClick={pedirProductoModal}>
                    <i className="fas fa-bolt"></i> Pedir Ahora
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Modal Formulario de Pedido */}
      <div className={`modal-producto-fondo${modalFormularioPedido ? ' active' : ''}`} onClick={(e) => e.target === e.currentTarget && cerrarFormularioPedido()} style={{ zIndex: 10001 }}>
        <div className="modal-producto-caja" style={{ maxWidth: '560px', padding: '0' }}>
          <button className="modal-boton-cerrar" onClick={cerrarFormularioPedido} style={{ zIndex: 2 }}>
            <svg viewBox="0 0 24 24"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
          </button>
          {productoPedido && (
            <div style={{ padding: '2.5rem 2rem 2rem' }}>
              <div style={{ textAlign: 'center', marginBottom: '1.8rem' }}>
                <div style={{ display: 'inline-flex', alignItems: 'center', justifyContent: 'center', width: '56px', height: '56px', borderRadius: '50%', background: 'linear-gradient(135deg, #ff0844, #800020)', marginBottom: '12px' }}>
                  <i className="fas fa-file-alt" style={{ color: '#fff', fontSize: '1.3rem' }}></i>
                </div>
                <h2 style={{ fontFamily: "'Rajdhani', sans-serif", fontSize: '1.5rem', fontWeight: 700, color: '#fff', margin: '0 0 4px' }}>Formulario de Pedido</h2>
                <p style={{ fontFamily: "'Inter', sans-serif", fontSize: '0.85rem', color: 'rgba(255,255,255,0.5)', margin: 0 }}>{productoPedido.nombre} — ${Number(productoPedido.precio).toLocaleString('es-CO')}</p>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '14px' }}>
                <div>
                  <label style={{ display: 'block', fontFamily: "'Rajdhani', sans-serif", fontSize: '0.8rem', fontWeight: 600, color: 'rgba(255,255,255,0.7)', marginBottom: '6px', textTransform: 'uppercase', letterSpacing: '1px' }}>Nombre Completo <span style={{ color: '#ff0844' }}>*</span></label>
                  <input type="text" placeholder="Ej: Juan Pérez" value={formularioPedido.nombreCompleto}
